import { createEffect } from 'solid-js';

// src/utils/compose-refs.ts
var isRefFn = (ref) => typeof ref === "function";
var setRefs = (refs, node) => {
  for (const ref of refs) {
    if (isRefFn(ref)) {
      ref(node);
    }
  }
};
function composeRefs(...refs) {
  let node = null;
  createEffect(() => {
    setRefs(refs, node);
  });
  return (el) => {
    node = el;
    setRefs(refs, el);
  };
}

export { composeRefs };
